import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse(`{"title":"Ben's Bites — 2026-04-14","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-14","date":"2026-04-14T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-14-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-14-bens-bites.md","lastUpdated":1779796674000}`),n={name:"research/ai-news/2026-04/2026-04-14-bens-bites.md"};function s(l,e,i,p,u,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-04-14" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-14 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-14" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-14&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="big-lab-leaks" tabindex="-1"><a href="https://www.bensbites.com/p/big-lab-leaks" target="_blank" rel="noreferrer">Big lab leaks</a> <a class="header-anchor" href="#big-lab-leaks" aria-label="Permalink to &quot;[Big lab leaks](https://www.bensbites.com/p/big-lab-leaks)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-14</em></p><p>Hey folks,</p><p>I’ll be heading to SF on Thursday — speaking at Stanford the week after. I’ll be delivering live the ‘how to use agents if you’re not technical’ course I’ve been working on (ahem, still working on).</p><p>I’ll be in town chatting to LPs (my 2 prev funds; 2.3x MOIC, 43% IRR (2023), and 4x MOIC, 28% IRR (2020)) and founders (I invest in AI dev tools and infra!) - let me know who I should try and meet or any cool things going on.</p><p>The <a href="https://x.com/marmaduke091/status/2043382991901147158" target="_blank" rel="noreferrer">latest leak from Claude-land</a> shows Anthropic is adding lovable-like features for building full-stack apps right inside Claude. Codex apparently had a similar leak (since deleted).</p><p>There’s a new term going around for products that agents can use - headless SaaS. <a href="https://x.com/levie/status/2043426157367095397" target="_blank" rel="noreferrer">Box’s CEO</a> says that “Enterprises will kick out vendors that don’t make it easy/economical for agents to use their product”. And you can’t just wrap your <a href="https://x.com/dharmesh/status/2043046723950436368" target="_blank" rel="noreferrer">APIs into MCP/CLIs</a> and call it a day.</p><p>Talks at AI Engineer were across the spectrum from “code is a liability” to “slow the fuck down”. Alex has a <a href="https://x.com/altryne/status/2043748676099866771" target="_blank" rel="noreferrer">good recap</a>.</p><p>Ben’s Bites is brought to you by <a href="https://www.cloudera.com/campaign/the-data-readiness-index-understanding-the-foundations-for-successful-ai?utm_medium=3rd-party&amp;utm_source=sponsored-content&amp;keyplay=AI-Anywhere&amp;utm_campaign=Thought-Leadership-Reports---AlwaysOn-FY27-Q1-GLOBAL-CT-Report-Data-Readiness-Index-Survey&amp;cid=701Ui00000tojqLIAQ&amp;utm_content=ben-bites" target="_blank" rel="noreferrer">Cloudera</a></p><p>AI is booming, but ROI is lagging. The problem isn’t AI—it’s data readiness. Most enterprises aren’t as prepared as they think. See where things really stand in <a href="https://www.cloudera.com/campaign/the-data-readiness-index-understanding-the-foundations-for-successful-ai?utm_medium=3rd-party&amp;utm_source=sponsored-content&amp;keyplay=AI-Anywhere&amp;utm_campaign=Thought-Leadership-Reports---AlwaysOn-FY27-Q1-GLOBAL-CT-Report-Data-Readiness-Index-Survey&amp;cid=701Ui00000tojqLIAQ&amp;utm_content=ben-bites" target="_blank" rel="noreferrer">Cloudera’s Data Readiness Index</a>.</p><p>Headlines</p><p><a href="https://x.com/felixrieseberg/status/2042272870940987422" target="_blank" rel="noreferrer">Claude Cowork</a> is now generally available - out of research preview after 12 weeks with millions of users. Also, <a href="https://x.com/claudeai/status/2042670341915295865" target="_blank" rel="noreferrer">Claude for Word</a> is in beta - draft, edit, and revise documents from the Word sidebar with edits showing up as tracked changes. (Team and Enterprise plans)</p><p>New Claude Code features - <a href="https://x.com/trq212/status/2042671370186973589" target="_blank" rel="noreferrer">/ultraplan</a> lets you build and edit a plan on the web, then run it in your terminal. The <a href="https://x.com/noahzweben/status/2042332268450963774" target="_blank" rel="noreferrer">Monitor tool</a> lets Claude watch for events in the background instead of constantly checking - saves a lot of tokens. Plus, an <a href="https://claude.com/blog/the-advisor-strategy" target="_blank" rel="noreferrer">advisor strategy</a> on the Claude dev platform that pairs Opus with Sonnet for better performance at similar/cheaper costs.</p><p><a href="https://community.openai.com/t/introducing-new-100-month-pro-tier/1378752" target="_blank" rel="noreferrer">OpenAI added a new $100 plan</a>. Their own wording is too complex, so I’m <a href="https://x.com/theo/status/2043078809843626093" target="_blank" rel="noreferrer">stealing Theo’s</a>. Basically, $100 plan = 5x compute, $200 = 10x compute (where $20 plan = 1x). The bigger plans have 2x boost till May 31st, so effectively, $100 = 10x and $200 = 20x compute.</p><p>LlamaParse was built to tackle your most complex PDFs with the highest accuracy &amp; the lowest cost. Now we want to put that to the test. Submit your ugliest PDF (dense contracts, financial tables, etc.), and judge the output vs your current OCR to win a Mac Mini. <a href="https://landing.llamaindex.ai/doc-challenge-spring-2026?utm_source=sponsor&amp;utm_medium=bensbites&amp;utm_campaign=bb-newsletter-2026-04-14" target="_blank" rel="noreferrer">Can your doc outsmart LlamaParse?</a>*</p><p>My feed</p><p>Anyone can make a game now. Yoroll turns a rough idea into a branching, playable video-native game. <a href="https://yoroll.ai/" target="_blank" rel="noreferrer">Join waitlist to try.</a>*</p><p><a href="https://x.com/cursor_ai/status/2042287192895267212" target="_blank" rel="noreferrer">Cursor cloud agents</a> can now attach screenshots and demos to PRs they open. Your team reviews the artifacts directly in GitHub.</p><p><a href="https://x.com/Shopify/status/2042335627862032754" target="_blank" rel="noreferrer">Shopify AI Toolkit</a> - manage your Shopify store with your favourite agent. Works with Claude Code, Codex, Cursor, VS Code, and more. (<a href="https://shopify.dev/docs/apps/build/ai-toolkit" target="_blank" rel="noreferrer">docs</a>)</p><p><a href="https://x.com/nicoalbanese10/status/2043745569278251112" target="_blank" rel="noreferrer">Open Agents</a> by Vercel - open-source template for building coding agents.</p><p><a href="https://factory.ai/news/missions-architecture" target="_blank" rel="noreferrer">How Missions work</a> - from the Factory team.</p><p><a href="https://x.com/a16z/status/2043732774595748198" target="_blank" rel="noreferrer">Agentic parenting</a> and <a href="https://x.com/clairevo/status/2043862637851881756" target="_blank" rel="noreferrer">TradClaw</a>.</p><p><a href="https://blog.langchain.com/the-anatomy-of-an-agent-harness/" target="_blank" rel="noreferrer">The anatomy of an agent harness</a> and a tutorial/walkthrough to <a href="https://www.youtube.com/watch?v=I82j7AzMU80" target="_blank" rel="noreferrer">build your own harness</a>.</p><p><a href="https://x.com/thatguybg/status/2042660471988457688" target="_blank" rel="noreferrer">How I became technical AF</a>.</p><p>Personal wiki tools inspired by Karpathy’s knowledge base idea - <a href="https://x.com/nikunj/status/2042020992969744702" target="_blank" rel="noreferrer">LLMwiki</a>, <a href="https://x.com/ansubkhan/status/2043334810505195944" target="_blank" rel="noreferrer">Wiki OS</a>, <a href="https://x.com/ChanningAllen/status/2042640867006029973" target="_blank" rel="noreferrer">Hatch</a>, and <a href="https://x.com/garrytan/status/2042497872114090069" target="_blank" rel="noreferrer">GBrain</a>.</p><p><a href="https://x.com/alokbishoyi97/status/2043251378374557824" target="_blank" rel="noreferrer">Evo</a>, another Karpathy-inspired CC plugin, optimises your code through experiments.</p><p>Ramp says their <a href="https://x.com/geoffintech/status/2042002590758572377" target="_blank" rel="noreferrer">entire company is AI-pilled</a>. They even built a new <a href="https://x.com/sebgoddijn/status/2042285915435937816" target="_blank" rel="noreferrer">internal product called Glass</a> to give every employee an AI coworker.</p><p><a href="https://getdesign.md" target="_blank" rel="noreferrer">getdesign.md</a> - browse design systems of popular applications as markdown files. Preview instantly, install with one command.</p><p><a href="https://x.com/aquavoice/status/2042105774449795182" target="_blank" rel="noreferrer">Aqua Voice</a> - premium voice keyboard for every app on your phone. Now on iOS.</p><p><a href="https://x.com/dinnaiii/status/2042257371645247716" target="_blank" rel="noreferrer">Gitinspect</a> - replace “hub” with “inspect” on any GitHub URL to chat with the repo. Runs in the browser, everything stays local.</p><p><a href="https://blog.cloudflare.com/sandbox-ga/" target="_blank" rel="noreferrer">Cloudflare Sandboxes</a> are generally available - comes with a terminal, interpreter, live preview URLs &amp; secure credentials. Sleeps when idle and wakes on demand.</p><p>Afters</p><p>@supabase\\n\\nit&#39;s a set of instructions that teach agents how to build with Supabase correctly, including:\\n\\n◆ Security and RLS\\n◆ Docs and product knowledge\\n◆ Schema management\\n◆ CLI + MCP instructions &quot;,&quot;username&quot;:&quot;kiwicopple&quot;,&quot;name&quot;:&quot;Paul Copplestone - e/postgres&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1664343166630109202/xcBMGPSE_normal.jpg%22,%22date%22:%222026-04-09T17:15:53.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://pbs.substack.com/media/HFesT9ibIAA6PXa.jpg%22,%22link_url%22:%22https://t.co/MUXI5nhb6e%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:29,%22retweet_count%22:46,%22like_count%22:564,%22impression_count%22:66220,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1664343166630109202/xcBMGPSE_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-09T17:15:53.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://pbs.substack.com/media/HFesT9ibIAA6PXa.jpg&quot;,&quot;link_url&quot;:&quot;https://t.co/MUXI5nhb6e&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:29,&quot;retweet_count&quot;:46,&quot;like_count&quot;:564,&quot;impression_count&quot;:66220,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail <a href="https://x.com/JayD0ubleu/status/2043421599580233903" target="_blank" rel="noreferrer">sourced from Twitter</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',43)])])}const m=t(n,[["render",s]]);export{d as __pageData,m as default};
